<template>
  <div class="app-shell">
    <aside class="sidebar card">
      <div><div class="eyebrow">Campus Repair Console</div><h2>{{ roleLabel(authState.user?.role) }}</h2><p class="subtle">{{ authState.user?.realName }} · {{ authState.user?.username }}</p></div>
      <nav class="nav-list"><button v-for="item in tabs" :key="item.key" class="nav-item" :class="{ active: activeTab===item.key }" @click="activeTab=item.key"><span>{{ item.icon }}</span>{{ item.label }}</button></nav>
      <button class="btn btn-ghost" @click="logout">退出登录</button>
    </aside>
    <main class="content-grid">
      <section class="hero card"><div><div class="eyebrow">Graduation Project Demo</div><h1>校园智能报修与派单系统</h1><p class="subtle">覆盖自然语言报修、进度追踪、派单处理与统计分析的完整演示。</p></div><div class="hero-metrics"><div class="hero-chip">系统：{{ health.system }}</div><div class="hero-chip">LLM：{{ health.llm }}</div></div></section>
      <section class="stats-grid"><StatCard label="总工单量" :value="stats.ticketCount??'-'" hint="概览统计"/><StatCard label="平均响应(分钟)" :value="stats.avgResponseMinutes??'-'" hint="响应效率"/><StatCard label="平均完成(小时)" :value="stats.avgCompleteHours??'-'" hint="闭环效率"/></section>

      <section v-if="isReporter&&activeTab==='submit'" class="card panel stack-lg"><div class="section-head"><div><div class="eyebrow">Reporter</div><h3>自然语言报修提交</h3></div><button class="btn btn-ghost" @click="loadReporter">刷新</button></div><label class="field"><span>报修描述</span><textarea v-model="reportForm.rawText" rows="5" placeholder="例如：宿舍A3-402空调不制冷，今晚要复习，请尽快处理。"></textarea></label><label class="field"><span>联系电话</span><input v-model.trim="reportForm.contactPhone" placeholder="13912345678"/></label><div class="cluster"><button class="btn btn-primary" :disabled="loading.submit" @click="submitTicket">{{ loading.submit?'提交中...':'提交报修' }}</button><span v-if="feedback.submit" class="feedback feedback-success">{{ feedback.submit }}</span></div></section>

      <section v-if="isReporter&&activeTab==='track'" class="card panel stack-lg"><div class="section-head"><div><div class="eyebrow">Reporter</div><h3>报修进度追踪</h3></div><button class="btn btn-ghost" @click="loadReporter">刷新</button></div><div v-if="reporterTickets.length" class="table-wrap"><table><thead><tr><th>工单号</th><th>位置</th><th>故障</th><th>状态</th><th>时间</th><th></th></tr></thead><tbody><tr v-for="item in reporterTickets" :key="item.ticketId"><td>{{ item.ticketNo }}</td><td>{{ item.locationText||'待解析' }}</td><td>{{ item.faultDesc||'原始文本待解析' }}</td><td><StatusPill :label="item.status"/></td><td>{{ formatTime(item.submittedAt) }}</td><td><button class="btn btn-ghost" @click="viewTicket(item.ticketId)">详情</button></td></tr></tbody></table></div><EmptyState v-else title="暂无报修记录" text="先提交一条自然语言报修。"/></section>

      <section v-if="isWorker&&activeTab==='tasks'" class="card panel stack-lg"><div class="section-head"><div><div class="eyebrow">Worker</div><h3>维修任务列表</h3></div><button class="btn btn-ghost" @click="loadWorker">刷新</button></div><div v-if="workerTasks.length" class="kanban-grid"><article v-for="item in workerTasks" :key="item.ticketId" class="ticket-card"><div class="ticket-card__head"><strong>{{ item.ticketNo }}</strong><StatusPill :label="item.status"/></div><p>{{ item.locationText||'待管理员补充位置' }}</p><small>{{ item.faultDesc||'待解析' }}</small><div class="cluster"><button class="btn btn-primary" @click="acceptTask(item.ticketId)">接单</button><button class="btn btn-ghost" @click="completeTask(item.ticketId)">完工</button></div></article></div><EmptyState v-else title="当前暂无任务" text="管理员派单后任务会出现在这里。"/></section>

      <section v-if="isAdmin&&activeTab==='dispatch'" class="card panel stack-lg"><div class="section-head"><div><div class="eyebrow">Admin</div><h3>派单监控与改派</h3></div><div class="cluster"><button class="btn btn-ghost" @click="loadAdmin">刷新</button><button class="btn btn-primary" @click="loadWorkers">维修池</button></div></div><div v-if="adminTickets.length" class="table-wrap"><table><thead><tr><th>工单号</th><th>状态</th><th>位置</th><th>故障</th><th>维修人</th><th>操作</th></tr></thead><tbody><tr v-for="item in adminTickets" :key="item.ticketId"><td>{{ item.ticketNo }}</td><td><StatusPill :label="item.status"/></td><td>{{ item.locationText||'待解析' }}</td><td>{{ item.faultDesc||'待解析' }}</td><td>{{ workerName(item.currentWorkerId) }}</td><td><div class="action-grid"><button class="btn btn-ghost" @click="viewTicket(item.ticketId)">详情</button><button class="btn btn-primary" @click="parseTicket(item.ticketId)">解析</button><button class="btn btn-primary" @click="autoDispatch(item.ticketId)">自动派单</button><button class="btn btn-ghost" @click="manualDispatch(item.ticketId)">改派</button><button v-if="['已完成','已评价'].includes(item.status)" class="btn btn-ghost" @click="closeTicket(item.ticketId)">关闭</button><button class="btn btn-danger" @click="deleteTicket(item.ticketId)">删除</button></div></td></tr></tbody></table></div><EmptyState v-else title="暂无管理工单" text="报修提交后管理员可在此监控。"/></section>

      <section v-if="isAdmin&&activeTab==='stats'" class="card panel stack-lg"><div class="section-head"><div><div class="eyebrow">Admin</div><h3>统计看板</h3></div><button class="btn btn-ghost" @click="loadStats">刷新</button></div><div class="dashboard-columns"><div class="mini-panel"><h4>分类分布</h4><ul class="metric-list"><li v-for="item in categoryStats" :key="item.name"><span>{{ item.name }}</span><strong>{{ item.count }}</strong></li></ul></div><div class="mini-panel"><h4>维修负载</h4><ul class="metric-list"><li v-for="item in workerLoad" :key="item.workerId"><span>{{ item.workerName }}</span><strong>{{ item.count }}</strong></li></ul></div><div class="mini-panel"><h4>消息中心</h4><ul class="metric-list"><li v-for="item in messages.slice(0,5)" :key="item.id"><span>{{ item.title }}</span><strong>{{ item.isRead?'已读':'未读' }}</strong></li></ul></div></div></section>

      <section class="card panel stack-lg"><div class="section-head"><div><div class="eyebrow">Flow Feedback</div><h3>流程反馈与详情面板</h3></div><button class="btn btn-ghost" @click="loadMessages">刷新消息</button></div><p v-if="feedback.global" class="feedback feedback-success">{{ feedback.global }}</p><p v-if="feedback.error" class="feedback feedback-error">{{ feedback.error }}</p><div v-if="ticketDetail" class="detail-board"><div><span>工单号</span><strong>{{ ticketDetail.ticketNo }}</strong></div><div><span>状态</span><StatusPill :label="ticketDetail.status"/></div><div><span>位置</span><strong>{{ ticketDetail.locationText||'待解析' }}</strong></div><div><span>故障描述</span><strong>{{ ticketDetail.faultDesc||ticketDetail.rawText }}</strong></div><div><span>紧急度</span><strong>{{ ticketDetail.urgencyLevel||'-' }}</strong></div><div><span>联系方式</span><strong>{{ ticketDetail.contactMasked||'-' }}</strong></div><div><span>提交时间</span><strong>{{ formatTime(ticketDetail.submittedAt) }}</strong></div></div><div v-if="ticketDetail" class="cluster"><button v-if="isReporter&&ticketDetail.status==='已完成'" class="btn btn-primary" @click="evaluateCurrent">提交评价</button><button v-if="isAdmin&&['已完成','已评价'].includes(ticketDetail.status)" class="btn btn-ghost" @click="closeCurrent">管理员关闭</button></div><EmptyState v-else title="尚未查看工单详情" text="在列表中点击详情即可查看。"/></section>
    </main>
  </div>
</template>

<script setup>
import { computed, onMounted, reactive, ref } from 'vue'
import { useRouter } from 'vue-router'
import http,{ unwrap } from '../api'
import { authState, clearAuth } from '../store/auth'
import { formatTime, roleLabel } from '../utils'
import StatusPill from '../components/StatusPill.vue'
import StatCard from '../components/StatCard.vue'
import EmptyState from '../components/EmptyState.vue'
const router=useRouter(),activeTab=ref('submit'),reporterTickets=ref([]),workerTasks=ref([]),adminTickets=ref([]),workers=ref([]),categoryStats=ref([]),workerLoad=ref([]),messages=ref([]),ticketDetail=ref(null)
const stats=reactive({ticketCount:'-',avgResponseMinutes:'-',avgCompleteHours:'-'}),health=reactive({system:'检测中',llm:'检测中'}),reportForm=reactive({rawText:'',contactPhone:''}),loading=reactive({submit:false}),feedback=reactive({submit:'',global:'',error:''})
const isReporter=computed(()=>authState.user?.role==='REPORTER'),isWorker=computed(()=>authState.user?.role==='WORKER'),isAdmin=computed(()=>authState.user?.role==='ADMIN')
const tabs=computed(()=>isAdmin.value?[{key:'dispatch',label:'派单监控',icon:'◎'},{key:'stats',label:'统计看板',icon:'▣'}]:isWorker.value?[{key:'tasks',label:'任务处理',icon:'◉'}]:[{key:'submit',label:'提交报修',icon:'✦'},{key:'track',label:'进度追踪',icon:'↗'}])
const reset=()=>{feedback.submit='';feedback.global='';feedback.error=''}; const workerName=(id)=>workers.value.find(i=>i.workerId===id)?.workerName||(id?`#${id}`:'未指派'); const logout=()=>{clearAuth();router.push('/login')}
async function safeRun(task,msg=''){reset();try{await task();if(msg)feedback.global=msg}catch(err){feedback.error=err.message||'操作失败'}}
async function loadHealth(){try{health.system=unwrap(await http.get('/system/health'));const llm=unwrap(await http.get('/llm/health'));health.llm=llm.provider||llm.status}catch{health.system='离线';health.llm='离线'}}
async function loadStats(){if(!isAdmin.value)return;Object.assign(stats,unwrap(await http.get('/admin/stats/overview')));categoryStats.value=unwrap(await http.get('/admin/stats/category-distribution'));workerLoad.value=unwrap(await http.get('/admin/stats/worker-load'))}
async function loadMessages(){messages.value=unwrap(await http.get('/messages?page=1&size=10')).records||[]}
async function loadReporter(){reporterTickets.value=unwrap(await http.get('/tickets/my?page=1&size=20')).records||[];await loadMessages()}
async function loadWorker(){workerTasks.value=unwrap(await http.get('/worker/tasks?page=1&size=20')).records||[];await loadMessages()}
async function loadAdmin(){adminTickets.value=unwrap(await http.get('/admin/tickets?page=1&size=20')).records||[];await loadStats();await loadMessages()}
async function loadWorkers(){if(isAdmin.value)workers.value=unwrap(await http.get('/admin/workers'))}
async function viewTicket(id){await safeRun(async()=>{ticketDetail.value=unwrap(await http.get(`/tickets/${id}`))})}
async function submitTicket(){loading.submit=true;await safeRun(async()=>{const d=unwrap(await http.post('/tickets',reportForm));feedback.submit=`报修提交成功，工单号：${d.ticketNo}`;reportForm.rawText='';reportForm.contactPhone='';await loadReporter();await viewTicket(d.ticketId);activeTab.value='track'});loading.submit=false}
async function acceptTask(id){await safeRun(async()=>{unwrap(await http.post(`/tickets/${id}/accept`));await loadWorker();await viewTicket(id)},'已接单，工单进入处理中')}
async function completeTask(id){const repairResult=window.prompt('请输入维修结果','已完成维修，设备恢复运行');if(!repairResult)return;await safeRun(async()=>{unwrap(await http.post(`/tickets/${id}/complete`,{repairResult}));await loadWorker();await viewTicket(id)},'维修结果已提交')}
async function parseTicket(id){await safeRun(async()=>{unwrap(await http.post('/llm/parse',{ticketId:id}));await loadAdmin();await viewTicket(id)},'LLM 解析完成')}
async function autoDispatch(id){await safeRun(async()=>{unwrap(await http.post(`/tickets/${id}/dispatch/auto`));await loadAdmin();await viewTicket(id)},'自动派单已执行')}
async function manualDispatch(id){if(!workers.value.length)await loadWorkers();const txt=workers.value.map(i=>`${i.workerId}:${i.workerName}`).join('\n');const v=window.prompt(`输入要改派的 workerId：\n${txt}`,workers.value[0]?.workerId||'');if(!v)return;await safeRun(async()=>{unwrap(await http.post(`/tickets/${id}/dispatch/manual`,{workerId:Number(v),reason:'前端人工改派'}));await loadAdmin();await viewTicket(id)},'人工改派成功')}
async function closeTicket(id){await safeRun(async()=>{unwrap(await http.post(`/tickets/${id}/close`));await loadAdmin();await viewTicket(id)},'工单已关闭')}
async function evaluateCurrent(){const comment=window.prompt('请输入评价内容','处理及时，服务很好');if(comment===null||!ticketDetail.value)return;await safeRun(async()=>{unwrap(await http.post(`/tickets/${ticketDetail.value.ticketId}/evaluate`,{score:5,comment}));await loadReporter();await viewTicket(ticketDetail.value.ticketId)},'评价已提交')}
async function closeCurrent(){if(!ticketDetail.value)return;await safeRun(async()=>{unwrap(await http.post(`/tickets/${ticketDetail.value.ticketId}/close`));await loadAdmin();await viewTicket(ticketDetail.value.ticketId)},'工单已关闭')}
async function deleteTicket(id){if(!window.confirm('确认删除该工单？删除后不可恢复。'))return;await safeRun(async()=>{unwrap(await http.post(`/admin/tickets/${id}/delete`));adminTickets.value=adminTickets.value.filter(i=>i.ticketId!==id);if(ticketDetail.value?.ticketId===id)ticketDetail.value=null},'工单已删除')}
onMounted(async()=>{await loadHealth();if(isReporter.value){activeTab.value='submit';await loadReporter()}else if(isWorker.value){activeTab.value='tasks';await loadWorker()}else{activeTab.value='dispatch';await loadWorkers();await loadAdmin()}})
</script>
